INSERT INTO "public"."organizations" ("id", "name", "username", "description", "website", "logo_url", "type", "join_code", "verified", "created_at", "created_by", "staff_join_token", "staff_join_token_created_at", "staff_join_token_expires_at", "auto_join_domain", "allowed_email_domains") VALUES
	('4e559bd7-8cbc-41c4-9541-50c4a8cf18c4', 'Demo Organizations', 'demo', 'This is just for demo organizations and what your org COULD look like. We have other advanced features, and depending on what you need/want we can always build custom plug ins specific for you, just let me know.', NULL, NULL, 'nonprofit', '908142', false, '2025-12-26 01:33:00.355628+00', NULL, NULL, NULL, NULL, NULL, NULL),
	('c3215a44-3fdf-4b99-85af-048c5ff3a2da', 'DVSR Dog Toys', 'dvsrdogs', 'Dog toy making group.', NULL, 'https://api.lets-assist.com/storage/v1/object/public/organization-logos/c3215a44-3fdf-4b99-85af-048c5ff3a2da.jpg', 'nonprofit', '308450', false, '2026-02-09 23:43:25.922278+00', 'ec320402-3ee3-48d4-ae3b-56646960c0bf', NULL, NULL, NULL, NULL, NULL),
	('26bc1fa3-7f83-403c-bde1-2737bb71ca79', 'Troop 941', 'troop941', 'Troop 941 is an exceptionally active Scouts BSA organization with over 150+ active scouts as of February 2025, serving the Pleasanton, California community for over two decades. Our mission is to instill character, citizenship, and personal fitness, preparing youth to make ethical and moral choices throughout their lives. We achieve this through a rigorous program that emphasizes outdoor adventure, dedicated community service, and youth leadership development, guiding our members on their journey to becoming responsible, world-class leaders.', 'https://troop941.org', 'https://api.lets-assist.com/storage/v1/object/public/organization-logos/26bc1fa3-7f83-403c-bde1-2737bb71ca79.jpg', 'nonprofit', '296144', false, '2025-10-27 17:05:59.730671+00', 'b6ee0559-a406-4992-b621-9c5af015adce', '589a8553-c4df-4738-8767-7c93627b2f10', '2026-03-01 06:42:20.847+00', '2026-03-08 06:42:20.847+00', 'troop941.org', NULL),
	('41853092-579b-4816-ae62-44d203b82408', 'Edutine Contra Costa', 'edutinecontracosta', 'Edutine is a free, student-led online tutoring platform connecting high-achieving high school tutors with students worldwide. Sessions are remote, personalized, and always free.', 'https://www.edutine.com', 'https://api.lets-assist.com/storage/v1/object/public/organization-logos/41853092-579b-4816-ae62-44d203b82408.jpg', 'nonprofit', '215797', false, '2026-01-17 00:32:29.568049+00', '82d3edc5-82ba-4554-8063-d325c24406e5', NULL, NULL, NULL, 'edutinereachout.com', NULL),
	('4a6af894-7591-40b7-be2c-68ead99a2006', 'Dougherty Valley High School', 'dvhs', 'Dougherty Valley High School, located in San Ramon, CA, is a top-ranked high school known for academic excellence, diverse programs, and student leadership. With strong STEM, arts, and athletics, DVHS empowers students to thrive and prepare for college and beyond.', 'https://dvhs.srvusd.net', 'https://fotdmeakexgrkronxlof.supabase.co/storage/v1/object/public/organization-logos/4a6af894-7591-40b7-be2c-68ead99a2006.jpg', 'school', '734466', true, '2025-06-26 02:24:50.090451+00', NULL, '826df5e3-2e23-448f-9bef-0fd038202cd1', '2026-01-13 18:43:07.198+00', '2026-02-12 18:43:07.198+00', NULL, NULL),
	('8a16415f-bdef-4e2c-88ad-67dd989da127', 'SRVUSD IT Demo', 'srvusdITdemo', 'A sample school organization designed to demonstrate how Let’s Assist helps manage volunteer programs, track service hours, organize events, and streamline communication for SRVUSD.', 'https://srvusd.net', 'https://api.lets-assist.com/storage/v1/object/public/organization-logos/8a16415f-bdef-4e2c-88ad-67dd989da127.jpg', 'school', '603487', false, '2026-03-03 07:37:02.349578+00', 'b6ee0559-a406-4992-b621-9c5af015adce', '95987c29-63a4-4d84-b90e-d76f1daf7bc3', '2026-03-03 07:39:20.518+00', '2027-03-03 07:39:20.517+00', 'srvusd.net', NULL),
	('f7198ef8-db95-4199-8070-438f776fe791', 'Windemere Ranch Middle School', 'wrms', 'Windemere Ranch Middle School in San Ramon, CA, offers a supportive and engaging environment for 6th–8th graders. With strong academics, STEM, arts, and leadership programs, WRMS helps students grow, explore interests, and prepare for future success.', 'https://wrms.srvusd.net', 'https://fotdmeakexgrkronxlof.supabase.co/storage/v1/object/public/organization-logos/f7198ef8-db95-4199-8070-438f776fe791.jpg', 'school', '363889', true, '2025-06-26 02:19:21.919517+00', '54941f39-c830-4842-a8df-34aa52fe47d1', NULL, NULL, NULL, NULL, NULL);
