	('828b4438-9fd7-4fa8-a748-4bf0f3f36036', 'b6ee0559-a406-4992-b621-9c5af015adce', 'HHESPTA - Astronomy Night', 'Hidden Hills Elementary School', '<p>Hello DVHS CSF team,</p><p>Hidden Hills PTA is looking for 4 CSF Volunteers for the Astronomy Night on 01/22/2026 from 5:15 pm to 7:15 pm.Kindly provide your First and Last name , Grade and Phone Number.</p><p>Please review the time and click on the button to sign up. Thank you!</p><p>Warm wishes</p><p>HHESPTA - President</p>', 'oneTime', 'qr-code', '2026-01-19 22:01:49.757454+00', '{"oneTime": {"date": "2026-01-30", "endTime": "19:15", "startTime": "17:15", "volunteers": 4}}', 'completed', false, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_828b4438-9fd7-4fa8-a748-4bf0f3f36036_cover_1768860110564.webp', '[]', '4e559bd7-8cbc-41c4-9541-50c4a8cf18c4', NULL, NULL, '{"text": "Hidden Hills Elementary School", "coordinates": {"latitude": 37.7646641, "longitude": -121.8936929}, "display_name": "12995 Harcourt Way, San Ramon, CA 94582, USA"}', false, 'dad83d6e-99e3-4685-bfd6-311e4dc00894', '{"oneTime": false}', '275ouiremm1496gv29kogib6bk', '2026-03-11 18:42:12.857+00', 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, true, true, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
