	('2ac81349-21fb-4b34-9fe8-fccc366d562b', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Bookmarks for a Cause', 'Valley View Park', '<p>Come create diy bookmarks with us to be gifted to senior centers and sold at school events!</p><p>supplies and food provided</p><ul class="list-disc list-outside ml-4"><li class="my-1"><p>no experience needed</p></li><li class="my-1"><p>bring a friend!</p></li></ul><p></p><p><em>Note: this is jst a mock and I took one of your old insta posts, and it''s also unlisted so dont worry, its just for you to see and sort of understand</em></p>', 'oneTime', 'qr-code', '2025-12-27 23:16:12.369312+00', '{"oneTime": {"date": "2026-01-15", "endTime": "18:00", "startTime": "16:00", "volunteers": 20}}', 'completed', false, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_2ac81349-21fb-4b34-9fe8-fccc366d562b_cover_1766877392091.png', '[]', '4e559bd7-8cbc-41c4-9541-50c4a8cf18c4', NULL, NULL, '{"text": "Valley View Park", "coordinates": {"latitude": 37.776768, "longitude": -121.9192216}, "display_name": "N Monarch Rd, San Ramon, CA 94582, USA"}', false, '999e38ee-a661-4d46-93fb-3bd3028c4fa1', '{"oneTime": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
