	('29600f5d-46dd-4b6b-b0d6-f8a73eaf26bc', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Beach Cleanup at Santa Cruz Beach', 'Santa Cruz Beach Boardwalk', '<p>Join us for a vital beach cleanup at Santa Cruz Beach this Saturday. We have two distinct roles to cover both the east and west sides of the beach, ensuring a thorough clean-up of our beautiful coastline. All supplies will be provided.</p>', 'sameDayMultiArea', 'qr-code', '2026-01-12 20:35:51.369397+00', '{"sameDayMultiArea": {"date": "2026-01-12", "roles": [{"name": "East Side Cleanup Crew", "endTime": "12:40", "startTime": "12:38", "volunteers": 25}, {"name": "West Side Cleanup Crew", "endTime": "12:45", "startTime": "12:40", "volunteers": 25}], "overallEnd": "12:45", "overallStart": "12:38"}}', 'completed', false, NULL, '[]', '4a6af894-7591-40b7-be2c-68ead99a2006', NULL, NULL, '{"text": "Santa Cruz Beach Boardwalk", "coordinates": {"latitude": 36.9645218, "longitude": -122.0166672}, "display_name": "400 Beach St, Santa Cruz, CA 95060, USA"}', false, '9b66731a-bf74-4886-89bd-50f5a829d5a2', '{"East Side Cleanup Crew": true, "West Side Cleanup Crew": false}', NULL, NULL, 'America/Los_Angeles', false, 'public', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
