	('bc6e2d5f-7952-416a-8332-c0181117422e', 'b6ee0559-a406-4992-b621-9c5af015adce', 'BV Fall Book Fair Volunteers', 'Bella Vista Elementary School', '<p><em>Note: This is just a mock and what it could look like from one of your old posts on CSF. It''s also an unlisted event so don''t worry it''s not on the main feed it''s just to demo what it could look like :)</em></p><p></p><p>High school volunteers needed to help with Bella Vista Elementary''s book fair. No experience necessary! Please review the available slots below and click on the button to sign up.</p><p></p><p>Please arrive <strong>ON TIME</strong> and expect to stay the full shift if you plan to sign up.</p>', 'sameDayMultiArea', 'qr-code', '2025-12-27 22:01:42.784481+00', '{"sameDayMultiArea": {"date": "2026-01-21", "roles": [{"name": "Library Rearrangement & Set-Up", "endTime": "15:00", "startTime": "14:00", "volunteers": 15}, {"name": "Fair Cleanup", "endTime": "20:00", "startTime": "19:00", "volunteers": 10}], "overallEnd": "20:00", "overallStart": "14:00"}}', 'upcoming', true, NULL, '[]', '4e559bd7-8cbc-41c4-9541-50c4a8cf18c4', NULL, NULL, '{"text": "Bella Vista Elementary School", "coordinates": {"latitude": 37.7519919, "longitude": -121.9186347}, "display_name": "1050 Trumpet Vine Ln, San Ramon, CA 94582, USA"}', false, 'ceabcbce-f7cb-4c61-a9b3-19e2e4ce01b1', '{"Fair Cleanup": false, "Library Rearrangement & Set-Up": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
