	('b88d9a6e-642c-44f4-94af-478dbd8a455d', 'b6ee0559-a406-4992-b621-9c5af015adce', 'test', 'test', '<p>test</p>', 'oneTime', 'qr-code', '2026-02-14 20:14:32.752942+00', '{"oneTime": {"date": "2026-02-15", "endTime": "17:00", "startTime": "09:00", "volunteers": 15}}', 'upcoming', true, NULL, '[]', NULL, NULL, NULL, '{"text": "test", "display_name": "test"}', false, 'd56bb4d4-66f9-4b4d-97e4-db8ada3c9fc8', '{"oneTime": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, true, true, NULL, NULL, NULL, true, true, 'project_waivers/b88d9a6e-642c-44f4-94af-478dbd8a455d/1771100074172_Volunteer_Waiver_2025.pdf', 'https://api.lets-assist.com/storage/v1/object/public/waiver-uploads/project_waivers/b88d9a6e-642c-44f4-94af-478dbd8a455d/1771100074172_Volunteer_Waiver_2025.pdf', '230ef101-60be-4224-b69d-fa1f1aa7d933', false, NULL),
	('606b7bdc-99db-4d28-bdb5-11205e3e7926', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Contra Costa Food Bank', 'Food Bank of Contra Costa & Solano', '<p><em>Note: This is a mock and I just made this to show what it COULD look like. I just went to one of your old instagram posts, and put in the details into here(the details I got from the Google Calendar). Also don''t worry, I made this an unlisted project so it won''t show up in the public feed it''s just for you to see.</em></p><p></p><p><strong>Attire: </strong>Closed toed shoes REQUIRED (or they will have to send you home),<strong> </strong>jeans or black pants (no sweats/track pants/leggings), NHS shirt or DVHS pride shirt. Dress in layers; we’ll be in a warehouse.</p><p><strong>Description: </strong>Students will help sort food for the food bank.<em> Please bring 5 (or more!) canned food items with you to the food bank to donate. </em>Ideas and suggestions will be sent out prior to the event</p><p></p><p><strong>**NOTE:</strong> <em>You</em> <em>cannot sign up if they have done food bank this semester)</em></p><p><strong>Points</strong>: 3</p>', 'oneTime', 'qr-code', '2025-12-26 15:52:53.512896+00', '{"oneTime": {"date": "2026-01-21", "endTime": "15:30", "startTime": "13:30", "volunteers": 20}}', 'upcoming', false, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_606b7bdc-99db-4d28-bdb5-11205e3e7926_cover_1766764378078.png', '[]', '4e559bd7-8cbc-41c4-9541-50c4a8cf18c4', NULL, NULL, '{"text": "Food Bank of Contra Costa & Solano", "coordinates": {"latitude": 38.0061499, "longitude": -122.0465115}, "display_name": "4010 Nelson Ave, Concord, CA 94520, USA"}', false, 'e35e1a93-b1b5-466f-aef9-a95e3f7af958', '{"oneTime": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
	('5a584d75-1531-4b12-8382-949230fb1dfe', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Gift Wrapping', 'Broadway Plaza', '<p>Join us for holiday gift wrapping at broadway plaza!Help wrap gifts for shoppers and spread some holiday cheer while supporting the American Red Cross through optional donations.<br><br>Hours- 2 DV📍Broadway Plaza Mall, Event Plaza (next to Macy’s, True Food Kitchen &amp; Starbucks)🗓️ December 23: 12–8 pm and December 24: 12–6 pm⏰ 2-hour shifts (only 4 volunteers per slot)</p><p></p><p><em>**please note this is an outdoor event, so dress accordingly</em></p><p></p><p><em>Note this is just a demo event and I just took it from one of your recent insta posts, and it''s also unlisted so don''t worry it''s just for you guys to see and understand what it would look like. There''s an option for anonymous and logged in signups only too, but I left it on anonymous incase you wanna test that as well.</em></p>', 'multiDay', 'qr-code', '2026-01-04 04:31:08.348248+00', '{"multiDay": [{"date": "2026-01-23", "slots": [{"endTime": "20:00", "startTime": "12:00", "volunteers": 4}]}, {"date": "2026-01-24", "slots": [{"endTime": "18:00", "startTime": "12:00", "volunteers": 4}]}]}', 'upcoming', false, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_5a584d75-1531-4b12-8382-949230fb1dfe_cover_1767501069234.png', '[]', '4e559bd7-8cbc-41c4-9541-50c4a8cf18c4', NULL, NULL, '{"text": "Broadway Plaza", "coordinates": {"latitude": 37.8958235, "longitude": -122.0574966}, "display_name": "1275 Broadway Plaza, Walnut Creek, CA 94596, USA"}', false, '44876a4f-9eb8-4cea-98f1-d215c40cc671', '{"2026-01-23-0": false, "2026-01-24-0": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
