	('934cb8b2-08de-4ae8-96e7-54c47cc448ae', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Beach Cleanup at Santa Cruz Beach', 'Santa Cruz Beach Boardwalk', '<p>Join us for a beach cleanup event at Santa Cruz Beach. We need about 20 volunteers to help pick up trash and recyclables to keep our coastline beautiful.</p>', 'oneTime', 'qr-code', '2026-03-06 22:59:49.061314+00', '{"oneTime": {"date": "2026-03-08", "endTime": "12:00", "startTime": "09:00", "volunteers": 20}, "multiDay": [{"date": "", "slots": [{"endTime": "17:00", "startTime": "09:00", "volunteers": 0}]}], "sameDayMultiArea": {"date": "", "roles": [{"name": "", "endTime": "17:00", "startTime": "09:00", "volunteers": 0}], "overallEnd": "17:00", "overallStart": "09:00"}}', 'upcoming', true, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_934cb8b2-08de-4ae8-96e7-54c47cc448ae_cover_1772837989202.jpeg', '[]', '26bc1fa3-7f83-403c-bde1-2737bb71ca79', NULL, NULL, '{"text": "Santa Cruz Beach Boardwalk", "coordinates": {"latitude": 36.9645218, "longitude": -122.0166672}, "display_name": "400 Beach St, Santa Cruz, CA 95060, USA"}', false, '03132bd9-385b-4d24-9992-35efc4fcf72e', '{"oneTime": false}', 'm1jrc7v3h77p3m7vsopi24blls', '2026-03-06 22:59:53.387+00', 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, true, true, 'project_waivers/934cb8b2-08de-4ae8-96e7-54c47cc448ae/1772837989583_Sample_Volunteer_Waiver.pdf', 'https://api.lets-assist.com/storage/v1/object/public/waiver-uploads/project_waivers/934cb8b2-08de-4ae8-96e7-54c47cc448ae/1772837989583_Sample_Volunteer_Waiver.pdf', '0360c364-0a01-448a-affe-7d0d94a194ae', false, NULL),
