	('26ccca28-4363-471e-a54c-3383bc1de8f1', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Volunteer Tutor for Paper Airplanes Tutoring Club', 'Dougherty Valley High School', 'Connect with teens affected by conflict in the Middle East as a volunteer English tutor and academic support provider for the Paper Airplanes Tutoring Club. Empower students by enhancing their language skills, boosting confidence, and opening doors to broader academic and career opportunities. Volunteers work one-on-one or in small groups, offering personalized guidance. Gain valuable teaching experience, develop leadership and communication skills, and deepen your understanding of global cultures. Foster cultural exchange and make a tangible impact.', 'sameDayMultiArea', 'signup-only', '2026-01-04 05:32:20.593632+00', '{"sameDayMultiArea": {"date": "2026-01-30", "roles": [{"name": "Math Tutoring", "endTime": "16:00", "startTime": "15:00", "volunteers": 8}, {"name": "Science Tutoring", "endTime": "17:00", "startTime": "16:00", "volunteers": 4}], "overallEnd": "17:00", "overallStart": "15:00"}}', 'upcoming', true, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_26ccca28-4363-471e-a54c-3383bc1de8f1_cover_1767504741532.png', '[]', NULL, NULL, NULL, '{"text": "Dougherty Valley High School", "coordinates": {"latitude": 37.7692188, "longitude": -121.9023247}, "display_name": "10550 Albion Rd, San Ramon, CA 94582, USA"}', false, 'c7a9e717-7cef-4a5e-a54b-c249ab22a189', '{"Math Tutoring": false, "Science Tutoring": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
