	('0187ec9b-bda3-446e-8904-76238de25cb6', 'b6ee0559-a406-4992-b621-9c5af015adce', 'testing', 'Dougherty Valley High School', '<p><strong>Use the following code for questions 12-13.</strong></p><p>ArrayList&lt;String&gt; a = new ArrayList&lt;String&gt;();</p><p>a.add("A");</p><p>a.add("B");</p><p>a.add("C");</p><p>a.add("D");</p><p>a.add("E");</p><p>String v = "aeiouAEIOU";</p><p>for(int i=0; i&lt;a.size(); i++)</p><p>&nbsp; &nbsp; if(v.indexOf(a.get(i))&gt;=0)</p><p>&nbsp; &nbsp; &nbsp; &nbsp; a.add(i,a.get(i));</p><p><a target="_blank" rel="noopener noreferrer" class="text-primary underline hover:text-primary/80 hover:cursor-pointer" href="http://S.o.pl">S.o.pl</a>(a.size());</p><p>&nbsp;</p><p>12. What is a after 3 iterations?*</p>', 'oneTime', 'qr-code', '2026-01-21 20:33:24.05316+00', '{"oneTime": {"date": "2026-01-21", "endTime": "17:00", "startTime": "12:50", "volunteers": 3}}', 'upcoming', true, NULL, '[]', NULL, NULL, NULL, '{"text": "Dougherty Valley High School", "coordinates": {"latitude": 37.7692188, "longitude": -121.9023247}, "display_name": "10550 Albion Rd, San Ramon, CA 94582, USA"}', false, 'b9d5cdba-4e13-405d-9cee-5522dc55ca85', '{"oneTime": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, true, true, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
