	('7aae298c-de0b-4455-a9a5-322b716a01bc', 'ec320402-3ee3-48d4-ae3b-56646960c0bf', 'Fruit Gleaning Project', 'Walnut Creek', '<p>Help harvest fresh fruit that would otherwise go to waste. This fruit will be donated to local food banks. Please wear comfortable clothing and closed-toe shoes.</p>', 'sameDayMultiArea', 'qr-code', '2026-02-09 23:35:36.459489+00', '{"sameDayMultiArea": {"date": "2026-02-14", "roles": [{"name": "Adult Shift Lead", "endTime": "11:00", "startTime": "09:00", "volunteers": 2}, {"name": "Shift Volunteer (adults and youth)", "endTime": "11:00", "startTime": "09:00", "volunteers": 20}], "overallEnd": "11:00", "overallStart": "09:00"}}', 'upcoming', true, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_7aae298c-de0b-4455-a9a5-322b716a01bc_cover_1770680138305.jpeg', '[]', NULL, NULL, NULL, '{"text": "Walnut Creek", "coordinates": {"latitude": 37.9100783, "longitude": -122.0651819}, "display_name": "Walnut Creek, CA, USA"}', false, '6c5b16e2-0809-4a96-8014-6015c68793ce', '{"Adult Shift Lead": false, "Shift Volunteer (adults and youth)": false}', NULL, NULL, 'America/Los_Angeles', false, 'public', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
	('25f50ad5-27d7-4a17-8f46-e326e6edeb50', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Santa Cruz Beach Boardwalk Cleanup', 'Santa Cruz Beach Boardwalk', 'Join us for a beach cleanup at the Santa Cruz Beach Boardwalk. We have two groups: West Side Garbage Collecting and East Side Garbage Collecting. Your participation will help keep our beautiful beach clean.', 'sameDayMultiArea', 'qr-code', '2025-10-30 01:08:19.375835+00', '{"sameDayMultiArea": {"date": "2025-10-29", "roles": [{"name": "West Side Garbage Collecting", "endTime": "18:30", "startTime": "18:27", "volunteers": 15}, {"name": "East Side Garbage Collecting", "endTime": "18:45", "startTime": "18:35", "volunteers": 20}], "overallEnd": "18:45", "overallStart": "18:20"}}', 'completed', true, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_25f50ad5-27d7-4a17-8f46-e326e6edeb50_cover_1761786502449.jpeg', '[]', '4a6af894-7591-40b7-be2c-68ead99a2006', NULL, NULL, '{"text": "Santa Cruz Beach Boardwalk", "coordinates": {"latitude": 36.9645218, "longitude": -122.0166672}, "display_name": "400 Beach St, Santa Cruz, CA 95060, USA"}', false, 'd777eca6-10f7-4146-8015-e46828aa60e1', '{"East Side Garbage Collecting": false, "West Side Garbage Collecting": true}', NULL, NULL, 'America/Los_Angeles', false, 'public', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
	('36d2a390-2e93-4cee-85fc-4e3bdad03a63', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Thorton Beach Cleanup', 'Thornton State Beach', '<p>Note, this is just a demo opportunity, and this isn''t actually on the Let''s Assist feed, it''s just to show you what it could look like. I just took one of your old instagram posts and then put it in here as a demo</p><p></p><p><strong>Meeting Spot</strong>: Look for our site captains table after the roundabout on thorton beach road where the walkway starts</p><p></p><p><strong>Supplies</strong>: Try bringing your own buckets and reusable gloves, extra gloves and buckets will be provided while supplies last. Bring extra layers, a hat, sunblock, water, and snacks.</p><p></p><p><strong>Transportation</strong>: Mission Coral will not be prroviding any transportation but we strongly recommend carpooling with friends.</p>', 'sameDayMultiArea', 'qr-code', '2025-12-26 01:43:43.302245+00', '{"sameDayMultiArea": {"date": "2026-01-14", "roles": [{"name": "East Side Pick Up Group", "endTime": "19:00", "startTime": "17:00", "volunteers": 20}, {"name": "West Side Pick Up Group", "endTime": "19:30", "startTime": "18:00", "volunteers": 18}], "overallEnd": "19:30", "overallStart": "17:00"}}', 'completed', false, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_36d2a390-2e93-4cee-85fc-4e3bdad03a63_cover_1766714256676.png', '[]', '4e559bd7-8cbc-41c4-9541-50c4a8cf18c4', NULL, NULL, '{"text": "Thornton State Beach", "coordinates": {"latitude": 37.6980773, "longitude": -122.4960046}, "display_name": "Thornton State Beach, Thornton Beach Rd, Daly City, CA 94015, USA"}', false, 'a2b04432-0b85-48f5-ad0d-87c727efd6a0', '{"East San Ramon Pick Up": false, "West San Ramon Pick Up": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
