	('dc173c32-5356-40bc-830e-a53c973cbf4b', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Sandwich Making', 'Room 1118', '<p>Hey Wildcats! Join us in room 1118 this Friday (4/18) after school to make sandwiches for the local homeless community! You will earn 1 CSF Non-drive point for participating in this activity. We hope to see you there! This will be during B Period.</p>', 'oneTime', 'qr-code', '2026-01-04 22:49:13.335252+00', '{"oneTime": {"date": "2026-01-23", "endTime": "17:00", "startTime": "09:00", "volunteers": 12}}', 'upcoming', true, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_dc173c32-5356-40bc-830e-a53c973cbf4b_cover_1767566954225.png', '[]', '4e559bd7-8cbc-41c4-9541-50c4a8cf18c4', NULL, NULL, '{"text": "Room 1118", "display_name": "Room 1118"}', false, '10013c01-eb1f-4b2f-9241-e458102aca3d', '{"oneTime": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
	('f5fb7a5c-52b9-40bc-bd3c-d7692593828b', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Test Event', 'test', '<p>This is a test event to ensure the system is working correctly.</p>', 'multiDay', 'qr-code', '2026-02-26 20:06:45.181716+00', '{"multiDay": [{"date": "2026-02-28", "slots": [{"endTime": "11:00", "startTime": "09:00", "volunteers": 5}, {"endTime": "15:00", "startTime": "13:00", "volunteers": 3}]}, {"date": "2026-03-01", "slots": [{"endTime": "11:00", "startTime": "09:00", "volunteers": 5}, {"endTime": "15:00", "startTime": "01:00", "volunteers": 2}]}]}', 'upcoming', false, NULL, '[]', NULL, NULL, NULL, '{"text": "test", "display_name": "test"}', false, 'ededd3c8-eb44-47a8-b3c1-e0bfdda98a33', '{"2026-02-28-0": false, "2026-02-28-1": false, "2026-03-01-0": false, "2026-03-01-1": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, true, true, NULL, NULL, NULL, true, true, 'project_waivers/f5fb7a5c-52b9-40bc-bd3c-d7692593828b/1772136408270_Volunteer_Liability_Waiver_SLS_Sample_Jul_6_2021.pdf', 'https://api.lets-assist.com/storage/v1/object/public/waiver-uploads/project_waivers/f5fb7a5c-52b9-40bc-bd3c-d7692593828b/1772136408270_Volunteer_Liability_Waiver_SLS_Sample_Jul_6_2021.pdf', '3fd3f5ee-c2c2-4ed4-accc-afd98868f8ec', false, NULL),
	('91cdef89-d369-47b3-a7d0-3a133ba6b21c', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Lucky Dog Rescue Adoption Event', '4500 Las Positas Rd', '<p>Hi! Please sign up for any of the slots! Show up at 9:20am please! <br><em>Note this is just a demo event  and it''s also unlisted so don''t worry it''s just for you guys to see and understand what it would look like. There''s an option for anonymous and logged in signups only too, but I left it on anonymous incase you wanna test that as well.</em></p>', 'oneTime', 'qr-code', '2026-01-16 06:52:56.34131+00', '{"oneTime": {"date": "2026-01-31", "endTime": "12:00", "startTime": "09:20", "volunteers": 6}}', 'upcoming', false, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_91cdef89-d369-47b3-a7d0-3a133ba6b21c_cover_1768546393293.webp', '[]', '4e559bd7-8cbc-41c4-9541-50c4a8cf18c4', NULL, NULL, '{"text": "4500 Las Positas Rd", "coordinates": {"latitude": 37.70069429999999, "longitude": -121.743102}, "display_name": "4500 Las Positas Rd, Livermore, CA 94551, USA"}', false, '35c2fbd7-a052-4893-9cd4-9acff1f5096e', '{"oneTime": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
	('f2a201ab-4e84-4250-a94e-07711c1dddff', 'b6ee0559-a406-4992-b621-9c5af015adce', 'test', 'test', '<p>test</p>', 'oneTime', 'qr-code', '2026-02-16 02:30:10.659909+00', '{"oneTime": {"date": "2026-02-16", "endTime": "17:00", "startTime": "09:00", "volunteers": 15}}', 'cancelled', true, NULL, '[]', NULL, 'not necessary', '2026-02-16 05:23:16.571+00', '{"text": "test", "display_name": "test"}', false, '0225eca7-9668-4535-94ea-2ff54e32abae', '{"oneTime": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, true, true, NULL, NULL, NULL, true, true, 'project_waivers/f2a201ab-4e84-4250-a94e-07711c1dddff/1771209013649_Shoreline_Waiver_Agreement.pdf', 'https://api.lets-assist.com/storage/v1/object/public/waiver-uploads/project_waivers/f2a201ab-4e84-4250-a94e-07711c1dddff/1771209013649_Shoreline_Waiver_Agreement.pdf', '9b084f00-4b9d-4d16-ac44-d58b62d078a8', false, NULL),
	('8e376257-2f34-43a5-bb93-6b0488e704ee', '337186dd-158a-49aa-ac17-831fba64f07f', 'Lenton Reconciliation 2026', 'St. Augustine Catholic Church', '<p>On Wednesday, March 18, CCOP will be having reconciliation sessions from 9:00 AM to 9:00 PM in the St. Augustine Church. There will be several priests available at different stations throughout the church.</p><p></p><p>We have been asked to help out as greeters. We will welcome those coming and direct them to one of the stations. In addition, we will help with taking down the stations afterwards. </p><p></p><p>Please review the time slots and volunteer if you can.</p>', 'sameDayMultiArea', 'manual', '2026-03-17 16:58:48.52116+00', '{"oneTime": {"date": "", "endTime": "17:00", "startTime": "09:00", "volunteers": 0}, "multiDay": [{"date": "", "slots": [{"name": "", "endTime": "17:00", "startTime": "09:00", "volunteers": 0}]}], "sameDayMultiArea": {"date": "2026-03-18", "roles": [{"name": "9:00 - 11:00", "endTime": "11:00", "startTime": "09:00", "volunteers": 3}, {"name": "11:00 - 1:00", "endTime": "13:00", "startTime": "11:00", "volunteers": 3}, {"name": "1:00 - 3:00", "endTime": "15:00", "startTime": "13:00", "volunteers": 3}, {"name": "3:00 - 5:00", "endTime": "17:00", "startTime": "15:00", "volunteers": 3}, {"name": "5:00 - 7:00", "endTime": "19:00", "startTime": "17:00", "volunteers": 3}, {"name": "7:00 - 9:00", "endTime": "21:00", "startTime": "19:00", "volunteers": 3}, {"name": "Cleanup", "endTime": "21:30", "startTime": "21:00", "volunteers": 3}], "overallEnd": "21:30", "overallStart": "09:00"}}', 'upcoming', false, NULL, '[]', NULL, NULL, NULL, '{"text": "St. Augustine Catholic Church", "coordinates": {"latitude": 37.6547376, "longitude": -121.8622385}, "display_name": "3999 Bernal Ave, Pleasanton, CA 94566, USA"}', false, '2d5f0775-ff3b-4911-896c-f1e3b73f81d4', '{"Cleanup": false, "1:00 - 3:00": false, "3:00 - 5:00": false, "5:00 - 7:00": false, "7:00 - 9:00": false, "11:00 - 1:00": false, "9:00 - 11:00": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, true, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
	('b1ad3b59-89e4-4bd9-ae59-aa327fbf83db', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Hearts4Hands Movie Fundraiser Volunteers', 'Dougherty Valley High School', '<p>Vounteering from 5-8:30 on october 24th for a movie fundraiser. Worth 3 total csf points. We will randomly pick 7-10 volunteers and let you know!&nbsp;</p><p></p><p><em>Note: this is just a mock and it''s unlisted too so its jst for you to figure out how it works and what it looks like</em></p>', 'sameDayMultiArea', 'qr-code', '2025-12-27 23:26:22.868504+00', '{"sameDayMultiArea": {"date": "2026-01-21", "roles": [{"name": "Fundraiser Set up", "endTime": "18:00", "startTime": "17:00", "volunteers": 7}, {"name": "Running the Fundraiser", "endTime": "19:30", "startTime": "18:00", "volunteers": 10}, {"name": "Funderaiser Cleanup", "endTime": "20:30", "startTime": "19:30", "volunteers": 8}], "overallEnd": "20:30", "overallStart": "17:00"}}', 'completed', false, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_b1ad3b59-89e4-4bd9-ae59-aa327fbf83db_cover_1766877996809.png', '[]', '4e559bd7-8cbc-41c4-9541-50c4a8cf18c4', NULL, NULL, '{"text": "Dougherty Valley High School", "coordinates": {"latitude": 37.7692188, "longitude": -121.9023247}, "display_name": "10550 Albion Rd, San Ramon, CA 94582, USA"}', false, '38d397f7-8a26-450e-89c6-2d157eb1202e', '{"Fundraiser Set up": false, "Funderaiser Cleanup": false, "Running the Fundraiser": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
