	('0488d1cf-6b77-4cf4-8a1f-93bdb53b1475', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Beach Boardwalk Cleanup', 'Santa Cruz Beach Boardwalk', 'Help keep the Santa Cruz beach boardwalk beautiful by participating in a cleanup event. We''ll focus on removing litter and debris from the sand and boardwalk areas.', 'multiDay', 'qr-code', '2026-03-08 02:22:24.879122+00', '{"oneTime": {"date": "2026-03-15", "endTime": "12:00", "startTime": "09:00", "volunteers": 30}, "multiDay": [{"date": "2026-03-07", "slots": [{"name": "Morning Registration", "endTime": "18:30", "startTime": "18:25", "volunteers": 15}, {"name": "Evening Registration", "endTime": "19:00", "startTime": "18:30", "volunteers": 5}]}, {"date": "2026-03-08", "slots": [{"name": "Morning Registration", "endTime": "17:00", "startTime": "09:00", "volunteers": 1}, {"name": "Lunch Registration", "endTime": "22:00", "startTime": "20:00", "volunteers": 1}]}], "sameDayMultiArea": {"date": "", "roles": [{"name": "", "endTime": "17:00", "startTime": "09:00", "volunteers": 0}], "overallEnd": "17:00", "overallStart": "09:00"}}', 'upcoming', false, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_0488d1cf-6b77-4cf4-8a1f-93bdb53b1475_cover_1772936545010.jpeg', '[]', NULL, NULL, NULL, '{"text": "Santa Cruz Beach Boardwalk", "coordinates": {"latitude": 36.9645218, "longitude": -122.0166672}, "display_name": "400 Beach St, Santa Cruz, CA 95060, USA"}', false, '918ffcd3-7837-4833-928b-2bb29f6a81cf', '{"2026-03-07-0": false, "2026-03-07-1": false, "2026-03-08-0": false, "2026-03-08-1": false}', 'pnfcfb4hpj34u62sgfisbbom8o', '2026-03-08 02:22:32.767+00', 'America/Los_Angeles', false, 'public', true, 'published', NULL, NULL, NULL, true, true, NULL, NULL, NULL, true, true, 'project_waivers/0488d1cf-6b77-4cf4-8a1f-93bdb53b1475/1772936545596_Sample_Volunteer_Waiver.pdf', 'https://api.lets-assist.com/storage/v1/object/public/waiver-uploads/project_waivers/0488d1cf-6b77-4cf4-8a1f-93bdb53b1475/1772936545596_Sample_