	('02b9bac9-cb30-4de5-9157-49b9db8a9d71', 'b6ee0559-a406-4992-b621-9c5af015adce', 'test pdf', 'San Jose', '<p><strong>test</strong></p>', 'oneTime', 'qr-code', '2026-03-02 01:33:32.256207+00', '{"oneTime": {"date": "2026-03-07", "endTime": "15:05", "startTime": "15:02", "volunteers": 15}}', 'upcoming', true, NULL, '[]', NULL, NULL, NULL, '{"text": "San Jose", "coordinates": {"latitude": 37.33874, "longitude": -121.8852525}, "display_name": "San Jose, CA, USA"}', false, 'eb5b8bc3-5585-4b0d-a65a-909b08560243', '{"oneTime": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, true, true, NULL, '6bcfd602-a53c-4491-a3a9-369b978a3c89', 3, false, true, NULL, NULL, NULL, false, '2026-03-07'),
	('40aa09fe-d177-4c77-8de2-47199e36ee22', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Dandiya Event', 'Thomas S. Hart Middle School', '<p>Come volunteer at a Dandiya event this SATURDAY, OCTOBER 4 to earn 3 CSF points. The event takes place at HART MIDDLE SCHOOL, and the dress code is Indian semi-formal. Timings vary, but slots begin at 2 PM</p><p><strong>EARN 3 CSF POINTS</strong></p><p></p><p><em>Note: This is just a mock up and I just took one of your old insta posts and put in those images and stuff. I didn''t have the exact slot details bc the SignUpGenius expired but I just made up a quick mock. Also don''t worry this event is unlisted so it''s not publicly on the feed, it''s just for you to sort of see and evaluate </em></p>', 'sameDayMultiArea', 'qr-code', '2025-12-28 03:27:29.501261+00', '{"sameDayMultiArea": {"date": "2026-01-24", "roles": [{"name": "Event Decoration & Set-Up", "endTime": "16:00", "startTime": "14:00", "volunteers": 20}, {"name": "Event Cleanup", "endTime": "19:30", "startTime": "19:00", "volunteers": 12}], "overallEnd": "19:30", "overallStart": "14:00"}}', 'upcoming', false, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_40aa09fe-d177-4c77-8de2-47199e36ee22_cover_1766892452950.png', '[]', '4e559bd7-8cbc-41c4-9541-50c4a8cf18c4', NULL, NULL, '{"text": "Thomas S. Hart Middle School", "coordinates": {"latitude": 37.6857354, "longitude": -121.896816}, "display_name": "4433 Willow Rd, Pleasanton, CA 94588, USA"}', false, 'f99ce200-feea-44e2-b75d-8aab8bacbc57', '{"Event Cleanup": false, "Event Decoration & Set-Up": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
	('5615342c-2add-4855-8701-f92a2552f680', 'be5c0095-6171-4843-ad43-b2a890d8d45e', 'Nick Maehr Eagle Project - Helping Knights of Columbus', '3999 Bernal Ave', '<p>Come help improve the local Knights of Columbus Council''s storage shed. There''s a lot to get done: moving equipment, installing shelves, using basic hand-held tools, and more! We need all the help we can get, so please lend a hand.</p>', 'multiDay', 'qr-code', '2025-12-30 20:01:42.527755+00', '{"multiDay": [{"date": "2026-01-10", "slots": [{"endTime": "13:00", "startTime": "10:00", "volunteers": 8}, {"endTime": "15:00", "startTime": "13:00", "volunteers": 6}]}, {"date": "2026-01-11", "slots": [{"endTime": "11:30", "startTime": "09:30", "volunteers": 8}, {"endTime": "14:00", "startTime": "11:30", "volunteers": 8}]}]}', 'completed', false, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_5615342c-2add-4855-8701-f92a2552f680_cover_1767124905269.png', '[]', '26bc1fa3-7f83-403c-bde1-2737bb71ca79', NULL, NULL, '{"text": "3999 Bernal Ave", "coordinates": {"latitude": 37.6548304, "longitude": -121.8620163}, "display_name": "3999 Bernal Ave, Pleasanton, CA 94566, USA"}', false, '6c1fbde5-e6a9-4f30-b5d7-d43c5d63a860', '{"2026-01-10-0": false, "2026-01-10-1": false, "2026-01-11-0": false, "2026-01-11-1": true}', NULL, NULL, 'America/Los_Angeles', false, 'public', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
	('b61efe11-b00e-4848-b9c5-d9741b52ea3a', '82d3edc5-82ba-4554-8063-d325c24406e5', 'Tutors for Edutine Contra Costa', 'Remote', '<p>Our dedicated team of tutors comprises passionate high school volunteers eager to make a difference. As a tutor, you’ll not only gain valuable experience but also have the opportunity to earn volunteer hours and prestigious awards such as the President’s Volunteer Service Award (PVSA), the Daily Point of Light Award, and the Edutine Volunteer of the Year Award.</p><p></p><p>To sign up, fill out this Google Form: <a target="_blank" rel="noopener noreferrer" class="text-primary underline hover:text-primary/80 hover:cursor-pointer" href="https://forms.gle/NWFWJ5ge3cNrjMNw6">https://forms.gle/NWFWJ5ge3cNrjMNw6</a></p>', 'oneTime', 'signup-only', '2026-01-17 00:39:12.3939+00', '{"oneTime": {"date": "2026-02-28", "endTime": "17:00", "startTime": "09:00", "volunteers": 20}}', 'upcoming', true, NULL, '[]', '41853092-579b-4816-ae62-44d203b82408', NULL, NULL, '{"text": "Remote", "display_name": "Remote"}', false, '7e061e8e-30f7-4714-86cf-58b7253f310e', '{"oneTime": false}', NULL, NULL, 'America/Los_Angeles', false, 'public', true, 'published', NULL, NULL, NULL, true, true, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
