	('35660ac8-a51d-4d4a-9f88-a46e617caab9', 'b6ee0559-a406-4992-b621-9c5af015adce', 'testing', 'asd', '<p>asd</p>', 'oneTime', 'qr-code', '2026-03-02 01:33:35.316677+00', '{"oneTime": {"date": "2026-03-22", "endTime": "17:00", "startTime": "09:00", "volunteers": 3}}', 'upcoming', true, NULL, '[]', NULL, NULL, NULL, '{"text": "asd", "display_name": "asd"}', false, '690d96a9-eaea-4e3c-bba2-7cbfd9746ddb', '{"oneTime": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, true, true, NULL, '9fdd2b3c-0631-4a1a-b963-c2b40c7815d4', 15, false, true, NULL, NULL, NULL, false, '2026-03-22'),
	('814af85e-c768-433e-900b-9ef3211e61e3', 'b6ee0559-a406-4992-b621-9c5af015adce', 'test pdf', 'San Jose', '<p><strong>test</strong></p>', 'oneTime', 'qr-code', '2026-03-08 09:11:57.481614+00', '{"oneTime": {"date": "2026-04-04", "endTime": "15:05", "startTime": "15:02", "volunteers": 15}}', 'upcoming', true, NULL, '[]', NULL, NULL, NULL, '{"text": "San Jose", "coordinates": {"latitude": 37.33874, "longitude": -121.8852525}, "display_name": "San Jose, CA, USA"}', false, 'a56b321b-384e-4dc8-b06a-a4d335f63cb2', '{"oneTime": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, true, true, NULL, '6bcfd602-a53c-4491-a3a9-369b978a3c89', 7, false, true, NULL, NULL, NULL, false, '2026-04-04'),
	('5ae4fbf3-0fdd-405a-bbb9-f994edd36a38', '337186dd-158a-49aa-ac17-831fba64f07f', 'Lenton Reconciliation 2026', 'St. Augustine Catholic Church', '<p>On Wednesday, May 18, CCOP will be having reconciliation sessions from 9:00 AM to 9:00 PM in the St. Augustine Church. There will be several priests available at different stations throughout the church.</p><p></p><p>We have been asked to help out as greeters. We will welcome those coming and direct them to one of the stations. In addition, we will help with taking down the stations afterwards. </p><p></p><p>Please review the time slots and volunteer if you can.</p>', 'oneTime', 'qr-code', '2026-03-17 02:37:25.730335+00', '{"oneTime": {"date": "2026-03-18", "endTime": "21:00", "startTime": "09:00", "volunteers": 12}, "multiDay": [{"date": "", "slots": [{"name": "", "endTime": "17:00", "startTime": "09:00", "volunteers": 0}]}], "sameDayMultiArea": {"date": "", "roles": [{"name": "", "endTime": "17:00", "startTime": "09:00", "volunteers": 0}], "overallEnd": "17:00", "overallStart": "09:00"}}', 'upcoming', false, NULL, '[]', NULL, NULL, NULL, '{"text": "St. Augustine Catholic Church", "coordinates": {"latitude": 37.6547376, "longitude": -121.8622385}, "display_name": "3999 Bernal Ave, Pleasanton, CA 94566, USA"}', false, 'c2d1366a-8629-4df0-b852-1a0885124f14', '{"oneTime": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, false, false, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
	('bd9c9819-7a06-4f37-bcb0-4c485445126f', 'b6ee0559-a406-4992-b621-9c5af015adce', 'NSDA Last Chance Quallifier', 'Online', '<p>Tournament Information:</p><p>Dates: September 6–8, 2025</p><p>Location: Online</p><p>Cost: $100</p><p>Form Deadline: August 18, 2025 at 11:59 PM — no late entries accepted.</p><p>Details &amp; Registration Links:</p><p><strong>Tournament Info:</strong> Tabroom Info (<a target="_blank" rel="noopener noreferrer" class="text-primary underline hover:text-primary/80 hover:cursor-pointer" href="https://www.tabroom.com/index/tourn/index.mhtml?tourn_id=36144">https://www.tabroom.com/index/tourn/index.mhtml?tourn_id=36144</a>)</p><p>Binding Commitment: Submitting this form is a binding commitment.</p><p>Form Instructions: Fill out the form carefully. Use correct spelling, punctuation, and capitalization throughout.</p><p>Drop Policy: To drop, email Bhargavi Mallajosyula at <a target="_blank" rel="noopener noreferrer" class="text-primary underline hover:text-primary/80 hover:cursor-pointer" href="mailto:bmallajosyula22@gmail.com">bmallajosyula22@gmail.com</a>.</p><p>Drop fees apply after the form closes.National Speech and Debate Season Opener (UKSO)</p><p>Dates: September 6–8, 2025</p>', 'multiDay', 'signup-only', '2026-03-13 00:06:00.565187+00', '{"multiDay": [{"date": "2026-04-24", "slots": [{"name": "LD", "endTime": "20:00", "startTime": "16:00", "volunteers": 2}, {"name": "PF", "endTime": "20:00", "startTime": "04:00", "volunteers": 2}]}, {"date": "2026-04-25", "slots": [{"name": "LD", "endTime": "20:00", "startTime": "08:00", "volunteers": 2}, {"name": "PF", "endTime": "17:00", "startTime": "09:00", "volunteers": 2}]}, {"date": "2026-04-26", "slots": [{"name": "LD", "endTime": "17:00", "startTime": "09:00", "volunteers": 2}, {"name": "PF", "endTime": "17:00", "startTime": "09:00", "volunteers": 2}]}]}', 'upcoming', true, NULL, '[]', '4a6af894-7591-40b7-be2c-68ead99a2006', NULL, NULL, '{"text": "Online", "display_name": "Online"}', false, 'b4d32616-c041-48d7-9525-21fb3c589616', '{"2026-04-24-0": false, "2026-04-24-1": false, "2026-04-25-0": false, "2026-04-25-1": false, "2026-04-26-0": false, "2026-04-26-1": false}', 'oas3ou1m3f4bvkm5lqg1tn59j4', '2026-03-13 00:06:07.115+00', 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, false, true, NULL, NULL, NULL, true, true, 'project_waivers/bd9c9819-7a06-4f37-bcb0-4c485445126f/1773360360911_Sample_Volunteer_Waiver.pdf', 'https://api.lets-assist.com/storage/v1/object/public/waiver-uploads/project_waivers/bd9c9819-7a06-4f37-bcb0-4c485445126f/1773360360911_Sample_Volunteer_Waiver.pdf', '863a3f4e-60bd-40a1-8ff6-c02222fc89b8', false, NULL),
	('c6a6d1ba-9ac6-4683-a5a4-77dade1e7a3f', 'b6ee0559-a406-4992-b621-9c5af015adce', 'testing', 'asd', '<p>asd</p>', 'oneTime', 'qr-code', '2026-03-22 03:43:53.96985+00', '{"oneTime": {"date": "2026-04-19", "endTime": "17:00", "startTime": "09:00", "volunteers": 3}}', 'upcoming', true, NULL, '[]', NULL, NULL, NULL, '{"text": "asd", "display_name": "asd"}', false, '6cee4927-7fb6-46b9-a617-8d873760b3b5', '{"oneTime": false}', NULL, NULL, 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, true, true, NULL, '9fdd2b3c-0631-4a1a-b963-c2b40c7815d4', 23, false, true, NULL, NULL, NULL, false, '2026-04-19'),
	('d941b7f5-f8b4-4fe0-a998-e8f3f8b2ca22', 'b6ee0559-a406-4992-b621-9c5af015adce', 'Camp Quail 2026 Volunteers', 'Quail Run Elementary School', '<p>Dear Teens and Parents, </p><p>We are getting ready to host camp quail 2026 on Friday, May 1, 2026 from 4:30-8:00p.</p><p> </p><p>We need outgoing, enthusiastic, fun and engaging camp counselors to help make Camp Quail a success! </p><p> </p><p>The following volunteer opportunities are meant for parents/teens, please sign up for the position you can fulfill. </p><p> </p><p>For Teens:</p><p>You will be responsible for the job described and will receive community volunteer hours for the job done once completed. </p><p> </p><p>For parents:</p><p><strong>You will be responsible for the job described and will receive one free admission for your child to attend.</strong></p><p><strong>***Please register your child in the camp quail SUG and we will reimburse the ticket amount after camp. This will ensure all kids information is orgenized in one place. </strong></p><p>Please review the available slots below and click on the button to sign up. Thank you!</p><p>*** Note that free admission for you child will ONLY be honored if you attend and serve as volunteer. If you arent able to fulfil your duty you will be chared admission and/or you child may not be able to participate duirng event</p>', 'sameDayMultiArea', 'qr-code', '2026-03-19 19:07:00.555333+00', '{"sameDayMultiArea": {"date": "2026-05-01", "roles": [{"name": "Teens Only! (REGISTRATION LEADERS)", "endTime": "18:00", "startTime": "16:00", "volunteers": 2}, {"name": "TEENS Only! - EVENT PHOTOS", "endTime": "19:30", "startTime": "16:30", "volunteers": 1}, {"name": "Parents Only! (GROUP LEADERS)", "endTime": "19:15", "startTime": "17:00", "volunteers": 5}, {"name": "Parents Only! (STATION LEADER)", "endTime": "19:15", "startTime": "17:00", "volunteers": 5}, {"name": "Teens Only! (EVENT FLOATERS)", "endTime": "20:30", "startTime": "17:00", "volunteers": 2}, {"name": "Teens Only! (GROUP ASSISTANTS)", "endTime": "20:15", "startTime": "17:00", "volunteers": 5}, {"name": "Teens Only! (STATION HELPER)", "endTime": "20:15", "startTime": "17:00", "volunteers": 5}, {"name": "Parents (CAMP FLOATERS)", "endTime": "20:30", "startTime": "17:30", "volunteers": 2}, {"name": "Parents ONLY! ( DINNER SET UP/PIZZA RUN)", "endTime": "19:30", "startTime": "17:30", "volunteers": 5}], "overallEnd": "20:30", "overallStart": "16:00"}}', 'upcoming', true, 'https://api.lets-assist.com/storage/v1/object/public/project-images/project_d941b7f5-f8b4-4fe0-a998-e8f3f8b2ca22_cover_1773947221131.jpeg', '[]', '4e559bd7-8cbc-41c4-9541-50c4a8cf18c4', NULL, NULL, '{"text": "Quail Run Elementary School", "coordinates": {"latitude": 37.7628743, "longitude": -121.9142774}, "display_name": "4000 Goldenbay Ave, San Ramon, CA 94582, USA"}', false, '6043781c-428c-4a74-ab0d-50c19f51a413', '{"Parents (CAMP FLOATERS)": false, "TEENS Only! - EVENT PHOTOS": false, "Teens Only! (EVENT FLOATERS)": false, "Teens Only! (STATION HELPER)": false, "Parents Only! (GROUP LEADERS)": false, "Parents Only! (STATION LEADER)": false, "Teens Only! (GROUP ASSISTANTS)": false, "Teens Only! (REGISTRATION LEADERS)": false, "Parents ONLY! ( DINNER SET UP/PIZZA RUN)": false}', 'jeu7vmgpfmcigumocik7oq4a94', '2026-03-19 19:07:10.573+00', 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, true, true, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL),
	('4c8f1011-526e-4c18-8de0-169eb253c35a', 'b6ee0559-a406-4992-b621-9c5af015adce', 'DVHS Stitch a Smile Bookmarks', 'San Ramon Library - Contra Costa County Library', '<p>Hey CSF!<br /><br />Join DV Stitch a Smile to make crochet bookmarks!<br />1 bookmark = 1 nondrive point <strong>(3 max)</strong></p>', 'oneTime', 'qr-code', '2026-03-12 23:16:46.775861+00', '{"oneTime": {"date": "2026-03-13", "endTime": "15:00", "startTime": "13:00", "volunteers": 15}, "multiDay": [{"date": "", "slots": [{"name": "", "endTime": "17:00", "startTime": "09:00", "volunteers": 0}]}], "sameDayMultiArea": {"date": "", "roles": [{"name": "", "endTime": "17:00", "startTime": "09:00", "volunteers": 0}], "overallEnd": "17:00", "overallStart": "09:00"}}', 'cancelled', false, NULL, '[]', '4e559bd7-8cbc-41c4-9541-50c4a8cf18c4', 'made a mistake in making the event :(', '2026-03-12 23:17:56.119+00', '{"text": "San Ramon Library - Contra Costa County Library", "coordinates": {"latitude": 37.7643745, "longitude": -121.9532807}, "display_name": "100 Montgomery St, San Ramon, CA 94583, USA"}', false, '302f1485-d0ec-4373-921c-6418a6e66b2e', '{"oneTime": false}', 'q11ano5kum3m4lbp3vo499kags', '2026-03-12 23:17:59.123+00', 'America/Los_Angeles', false, 'unlisted', true, 'published', NULL, NULL, NULL, true, true, NULL, NULL, NULL, false, true, NULL, NULL, NULL, false, NULL);
